import com.google.mlkit.nl.entityextraction.EntityExtraction
import com.google.mlkit.nl.entityextraction.EntityExtractionParams
import com.google.mlkit.nl.entityextraction.EntityExtractor
import com.google.mlkit.nl.entityextraction.EntityAnnotation
import kotlinx.coroutines.suspendCancellableCoroutine
import kotlin.coroutines.resume
import kotlin.coroutines.resumeWithException

data class ExtractedEntity(
    val text: String,
    val type: Int,        // Entity.TYPE_DATE_TIME, TYPE_ADDRESS, etc.
    val confidence: Float
)

class MlKitNluClient {
    private val extractor: EntityExtractor =
        EntityExtraction.getClient(
            com.google.mlkit.nl.entityextraction.EntityExtractorOptions
                .Builder(com.google.mlkit.nl.entityextraction.EntityExtractorOptions.ENGLISH)
                .build()
        )

    suspend fun downloadModelIfNeeded() = suspendCancellableCoroutine<Unit> { cont ->
        extractor.downloadModelIfNeeded()
            .addOnSuccessListener { cont.resume(Unit) }
            .addOnFailureListener { cont.resumeWithException(it) }
    }

    suspend fun extractEntities(text: String): List<ExtractedEntity> =
        suspendCancellableCoroutine { cont ->
            val params = EntityExtractionParams.Builder(text).build()
            extractor
                .annotate(params)
                .addOnSuccessListener { annotations ->
                    val entities = annotations.flatMap { annotation ->
                        annotation.entities.map { entity ->
                            ExtractedEntity(
                                text = annotation.annotatedText,
                                type = entity.type,
                                confidence = annotation.entities
                                    .maxOf { it.confidence ?: 0f }
                            )
                        }
                    }
                    cont.resume(entities)
                }
                .addOnFailureListener { cont.resumeWithException(it) }
        }
}

import android.content.Context
import android.net.ConnectivityManager
import android.net.NetworkCapabilities

sealed interface NluResult {
    data class OnDevice(
        val entities: List<ExtractedEntity>,
        val source: String = "ml-kit"
    ) : NluResult

    data class Cloud(
        val query: String,
        val reason: RoutingReason
    ) : NluResult
}

enum class RoutingReason { LOW_CONFIDENCE, COMPLEX_QUERY, MULTI_TURN }

class HybridNluRouter(
    private val context: Context,
    private val mlKit: MlKitNluClient,
    private val confidenceThreshold: Float = 0.85f,
    private val complexityWordLimit: Int = 20
) {
    suspend fun route(
        text: String,
        conversationTurnCount: Int = 0
    ): NluResult {
        // Multi-turn conversations always go to Claude — context matters
        if (conversationTurnCount > 1) {
            return NluResult.Cloud(text, RoutingReason.MULTI_TURN)
        }

        val entities = mlKit.extractEntities(text)

        // No entities found on a short query → try ML Kit anyway but flag for escalation
        val maxConfidence = entities.maxOfOrNull { it.confidence } ?: 0f
        val wordCount = text.trim().split(Regex("\\s+")).size
        val isQuestion = text.trimEnd().endsWith('?')
        val isComplex = wordCount > complexityWordLimit || (isQuestion && entities.isEmpty())

        return when {
            isComplex -> NluResult.Cloud(text, RoutingReason.COMPLEX_QUERY)
            maxConfidence < confidenceThreshold && entities.isNotEmpty() -> {
                // Extracted something but not confident — escalate if online
                if (isOnline()) NluResult.Cloud(text, RoutingReason.LOW_CONFIDENCE)
                else NluResult.OnDevice(entities)
            }
            entities.isNotEmpty() -> NluResult.OnDevice(entities)
            // No entities at all on a simple declarative → return empty; Claude adds no value here
            else -> NluResult.OnDevice(emptyList())
        }
    }

    private fun isOnline(): Boolean {
        val cm = context.getSystemService(ConnectivityManager::class.java)
        val cap = cm.getNetworkCapabilities(cm.activeNetwork) ?: return false
        return cap.hasCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET) &&
               cap.hasCapability(NetworkCapabilities.NET_CAPABILITY_VALIDATED)
    }
}

import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.flow.flowOn
import kotlinx.serialization.Serializable
import kotlinx.serialization.json.Json
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.toRequestBody

@Serializable
data class ProxyRequest(
    val query: String,
    val sessionToken: String,    // short-lived; obtained via biometric auth
    val routingReason: String
)

class ClaudeProxyClient(
    private val proxyBaseUrl: String,
    private val httpClient: OkHttpClient = OkHttpClient()
) {
    private val json = Json { ignoreUnknownKeys = true }

    fun streamQuery(request: ProxyRequest): Flow<String> = flow {
        val body = json.encodeToString(ProxyRequest.serializer(), request)
            .toRequestBody("application/json".toMediaType())

        val httpRequest = Request.Builder()
            .url("$proxyBaseUrl/nlu/query")
            .post(body)
            .header("Authorization", "Bearer ${request.sessionToken}")
            .header("Accept", "text/event-stream")
            .build()

        val response = httpClient.newCall(httpRequest).execute()
        if (!response.isSuccessful) {
            error("Proxy error ${response.code}: ${response.body?.string()}")
        }

        response.body?.use { responseBody ->
            responseBody.source().use { source ->
                while (!source.exhausted()) {
                    val line = source.readUtf8Line() ?: break
                    if (line.startsWith("data: ")) {
                        val data = line.removePrefix("data: ").trim()
                        if (data == "[DONE]") return@flow
                        // Parse SSE delta; emit only the text content
                        val delta = extractDelta(data)
                        if (delta.isNotEmpty()) emit(delta)
                    }
                }
            }
        }
    }.flowOn(Dispatchers.IO)

    private fun extractDelta(sseData: String): String = try {
        val root = json.parseToJsonElement(sseData)
        root.jsonObject["delta"]?.jsonObject
            ?.get("text")?.jsonPrimitive?.content ?: ""
    } catch (_: Exception) { "" }
}

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

sealed interface NluUiState {
    object Idle                           : NluUiState
    object Loading                        : NluUiState
    data class OnDeviceResult(
        val entities: List<ExtractedEntity>
    )                                     : NluUiState
    data class StreamingCloudResult(
        val accumulatedText: String,
        val isComplete: Boolean = false
    )                                     : NluUiState
    data class Error(val message: String) : NluUiState
}

class HybridNluViewModel(
    private val router: HybridNluRouter,
    private val proxyClient: ClaudeProxyClient,
    private val sessionToken: String
) : ViewModel() {

    private val _state = MutableStateFlow<NluUiState>(NluUiState.Idle)
    val state: StateFlow<NluUiState> = _state.asStateFlow()

    private var turnCount = 0

    fun process(userText: String) {
        viewModelScope.launch {
            _state.value = NluUiState.Loading
            turnCount++

            try {
                when (val result = router.route(userText, turnCount)) {
                    is NluResult.OnDevice -> {
                        _state.value = NluUiState.OnDeviceResult(result.entities)
                    }
                    is NluResult.Cloud -> {
                        val request = ProxyRequest(
                            query = result.query,
                            sessionToken = sessionToken,
                            routingReason = result.reason.name
                        )
                        var accumulated = ""
                        proxyClient.streamQuery(request).collect { delta ->
                            accumulated += delta
                            _state.update {
                                NluUiState.StreamingCloudResult(
                                    accumulatedText = accumulated
                                )
                            }
                        }
                        _state.update {
                            (it as? NluUiState.StreamingCloudResult)
                                ?.copy(isComplete = true) ?: it
                        }
                    }
                }
            } catch (e: Exception) {
                _state.value = NluUiState.Error(e.message ?: "Unknown error")
            }
        }
    }

    fun reset() {
        turnCount = 0
        _state.value = NluUiState.Idle
    }
}

import com.google.mlkit.nl.languageid.LanguageIdentification
import com.google.mlkit.nl.languageid.LanguageIdentifier

class LanguageGate(
    private val supportedOnDeviceLangs: Set<String> = setOf("en", "de", "fr", "es", "zh")
) {
    private val identifier: LanguageIdentifier =
        LanguageIdentification.getClient()

    suspend fun shouldUseOnDevice(text: String): Boolean =
        suspendCancellableCoroutine { cont ->
            identifier.identifyLanguage(text)
                .addOnSuccessListener { languageCode ->
                    // "und" means undetermined — escalate to Claude
                    val use = languageCode != LanguageIdentifier.UNDETERMINED_LANGUAGE_TAG &&
                              languageCode in supportedOnDeviceLangs
                    cont.resume(use)
                }
                .addOnFailureListener {
                    // On ID failure, default to cloud path — safer than a wrong on-device result
                    cont.resume(false)
                }
        }
}

import androidx.room.*
import androidx.work.*

@Entity(tableName = "pending_nlu_queries")
data class PendingQuery(
    @PrimaryKey(autoGenerate = true) val id: Long = 0,
    val text: String,
    val reason: String,
    val timestampMs: Long
)

@Dao
interface PendingQueryDao {
    @Insert suspend fun enqueue(query: PendingQuery): Long
    @Query("SELECT * FROM pending_nlu_queries ORDER BY id ASC LIMIT 50")
    suspend fun dequeueAll(): List<PendingQuery>
    @Delete suspend fun remove(query: PendingQuery)
}

class DrainQueueWorker(
    ctx: Context, params: WorkerParameters
) : CoroutineWorker(ctx, params) {

    override suspend fun doWork(): Result {
        val db = AppDatabase.getInstance(applicationContext)
        val proxyClient = ClaudeProxyClient(proxyUrl = BuildConfig.PROXY_BASE_URL)
        val sessionToken = TokenStore.get(applicationContext) // decrypts from Keystore
            ?: return Result.failure()

        val pending = db.pendingQueryDao().dequeueAll()
        for (query in pending) {
            try {
                val request = ProxyRequest(query.text, sessionToken, query.reason)
                proxyClient.streamQuery(request).collect { /* store or notify */ }
                db.pendingQueryDao().remove(query)
            } catch (_: Exception) {
                return Result.retry()
            }
        }
        return Result.success()
    }
}

fun scheduleDrainOnConnectivity(context: Context) {
    val constraints = Constraints.Builder()
        .setRequiredNetworkType(NetworkType.CONNECTED)
        .build()
    val work = OneTimeWorkRequestBuilder<DrainQueueWorker>()
        .setConstraints(constraints)
        .build()
    WorkManager.getInstance(context).enqueueUniqueWork(
        "drain-nlu-queue",
        ExistingWorkPolicy.KEEP,
        work
    )
}

